import FeedbackItem from "./FeedbackItem";

function FeedbackList({
  feedbacks,
  onDelete
}) {

  if (feedbacks.length === 0) {

    return (
      <h3 className="empty">
        No Feedback Found
      </h3>
    );

  }

  return (

    <div>

      {feedbacks.map((feedback) => (

        <FeedbackItem
          key={feedback._id}
          feedback={feedback}
          onDelete={onDelete}
        />

      ))}

    </div>

  );

}

export default FeedbackList;
